		// Broadcast should receive truncated content
		const broadcastArg = vi.mocked(deps.wsHandler.broadcast).mock.calls[0]![0];
		expect(broadcastArg.type).toBe("tool_result");
		if (broadcastArg.type === "tool_result") {
