			expect(broadcastArg.isTruncated).toBe(true);
			expect(broadcastArg.fullContentLength).toBe(largeContent.length);
		}

		// Cache should also receive the truncated version
		const cacheArg = vi.mocked(deps.messageCache.recordEvent).mock
			.calls[0]![1];
		if (cacheArg.type === "tool_result") {
			expect(cacheArg.isTruncated).toBe(true);
		}
	});

