import { describe, expect, it, vi } from "vitest";
import { handleGetToolContent } from "../../src/lib/handlers/tool-content.js";
import type { HandlerDeps } from "../../src/lib/handlers/types.js";
import { ToolContentStore } from "../../src/lib/tool-content-store.js";
import type { RelayMessage } from "../../src/lib/types.js";

// ─── Minimal mock deps for this handler ─────────────────────────────────────

function createMockDeps(
	store: ToolContentStore,
): Pick<HandlerDeps, "wsHandler" | "toolContentStore"> {
	return {
		wsHandler: {
			broadcast: vi.fn(),
			broadcastExcept: vi.fn(),
			sendTo: vi.fn(),
		},
		toolContentStore: store,
	};
}

describe("handleGetToolContent", () => {
	it("returns stored content for a known toolId", async () => {
		const store = new ToolContentStore();
		store.store("tool-1", "full content here");
		const deps = createMockDeps(store);

		await handleGetToolContent(
			deps as unknown as HandlerDeps,
			"client-1",
			{ toolId: "tool-1" },
		);

		expect(deps.wsHandler.sendTo).toHaveBeenCalledWith("client-1", {
			type: "tool_content",
			toolId: "tool-1",
			content: "full content here",
		});
	});

	it("returns NOT_FOUND error for unknown toolId", async () => {
		const store = new ToolContentStore();
		const deps = createMockDeps(store);

		await handleGetToolContent(
			deps as unknown as HandlerDeps,
			"client-1",
			{ toolId: "nonexistent" },
		);

		expect(deps.wsHandler.sendTo).toHaveBeenCalledWith("client-1", {
			type: "error",
			code: "NOT_FOUND",
			message: "Full tool content not available",
		});
	});

	it("returns INVALID_PARAMS error when toolId is missing", async () => {
		const store = new ToolContentStore();
		const deps = createMockDeps(store);

		await handleGetToolContent(
			deps as unknown as HandlerDeps,
			"client-1",
			{},
		);

		expect(deps.wsHandler.sendTo).toHaveBeenCalledWith("client-1", {
			type: "error",
			code: "INVALID_PARAMS",
			message: "Missing toolId parameter",
		});
	});

	it("returns INVALID_PARAMS error when toolId is not a string", async () => {
		const store = new ToolContentStore();
		const deps = createMockDeps(store);

		await handleGetToolContent(
			deps as unknown as HandlerDeps,
			"client-1",
			{ toolId: 42 },
		);

		expect(deps.wsHandler.sendTo).toHaveBeenCalledWith("client-1", {
			type: "error",
			code: "INVALID_PARAMS",
			message: "Missing toolId parameter",
		});
	});
});

